import { Libc, isNully } from '@clockwork/common';
import { subLogger } from '@clockwork/logging';
import { Inject, getSelfProcessName } from '@clockwork/native';
import * as lz from 'lzutf8';

//base64 lzutf8 compressed elf files

const soFixer64 =
    '';

const soFixer32 =
    '';

const logger = subLogger('sodump');
const mutex_size = Process.pointerSize === 4 ? 24 : 40;
const mutex_addr = Memory.alloc(mutex_size);
mutex_addr.writeByteArray(new Array(mutex_size).fill(0));

const dumpedLibs = new Map();

Libc.pthread_mutex_init(mutex_addr, NULL);

function dropSoFixer(rawtext: string, fileName: string) {
    const procName = getSelfProcessName();
    const filesDir = `/data/data/${procName}`;
    const fullPath = `${filesDir}/${fileName}`;
    const sodata = lz.decompress(rawtext, {inputEncoding: 'Base64', outputEncoding: 'ByteArray' })
    //@ts-ignore
    File.writeAllBytes(fullPath, sodata);
    return fullPath;
}

function filterSo({ name, path }: { name: string; path: string }): boolean {
    return (
        path.startsWith('/data/') &&
        name !== 'base.odex' &&
        name !== 'soFixerArm32.so' &&
        name !== 'soFixerArm64.so'
    );
}

function dumpLibInternal(name: string) {
    console.log('nya?')
    const libso = Process.findModuleByName(name);
    if (libso == null) {
        logger.error({ tag: 'dumplib' }, `Module ${name} not found`);
        return -1;
    }

    const procName = getSelfProcessName();
    const filesDir = `/data/data/${procName}/`;
    const initialPath = `${name}_dump_${libso.base}.so`;
    const finalPath = `${name}_${libso.base}_${libso.size}.so`;
    const finalOut = `${filesDir}${finalPath}`;

    let sofixer = '';
    if (Process.arch === 'arm') {
        sofixer = dropSoFixer(soFixer32, 'SoFixer32.so');
    } else if (Process.arch === 'arm64') {
        sofixer = dropSoFixer(soFixer64, 'SoFixer64.so');
    } else {
        logger.error(`Not supported arch${Process.arch}`);
        return;
    }
    logger.info({ tag: 'fixer' }, sofixer);

    const dumpedFile = dumpSoFile(libso.base, libso.size, initialPath);
    logger.info({ tag: 'dumped' }, dumpedFile);

    const SoFixer = Memory.allocUtf8String(sofixer);
    Libc.chmod(SoFixer, 0o777);
    const hSoFixer = Libc.dlopen(SoFixer, 2);
    if (isNully(hSoFixer)) {
        logger.error(`Could not dlopen ${sofixer} x: ${Module.load(sofixer)}`);
        return;
    }

    try {
        const hDlMain = Libc.dlsym(hSoFixer, Memory.allocUtf8String('_Z6dlMainPcS_S_'));
        const dlMain = new NativeFunction(hDlMain, 'int', ['pointer', 'pointer', 'pointer']);
        dlMain(
            Memory.allocUtf8String(dumpedFile),
            Memory.allocUtf8String(`${libso.base}`),
            Memory.allocUtf8String(finalOut),
        );
        logger.info({tag: 'fixer'}, `${sofixer} -o ${finalOut}`)
        logger.info('success !~');
    } catch (error) {
        logger.error(`dlMain(): ${error}`);
    } finally {
        Libc.dlclose(hSoFixer);
    }
    return;

    // // ? unsure why this does not work, need to run the cmd yourself
    // const cmd = `su 0 ${sofixer} -s ${dumpedFile} -m ${libso.base} -o ${finalOut}`;
    // logger.info({ tag: 'cmd' }, cmd);
    // const Cmd = Memory.allocUtf8String(cmd);
    // const result = Libc.system(Cmd);
    // logger.info({ tag: 'system' }, `${result} ${finalOut}`);
    // const fd = Libc.popen(Cmd, Memory.allocUtf8String('r'));
    // if (!isNully(fd)) {
    //     const buffer = Memory.alloc(1024);
    //     while (!isNully(Libc.fgets(buffer, 1024, fd))) {
    //         logger.info({ tag: 'output' }, `${buffer.readCString()}`);
    //     }
    //     const result = Libc.pclose(fd);
    //     logger.info({ tag: 'execv' }, `${result} ${finalOut}`);
    // } else {
    //     logger.info({ tag: 'execv' }, `${fd} ${finalOut}`);
    // }
}

function dumpSoFile(ptr: NativePointer, size: number, file: string) {
    const procName = getSelfProcessName();
    const dumpsDir = `/data/data/${procName}/dumps`;
    Libc.mkdir(Memory.allocUtf8String(dumpsDir), 0o755);
    const outPath = `${dumpsDir}/${file}`;
    Memory.protect(ptr, size, 'rwx');
    const buffer = ptr.readByteArray(size);
    //@ts-ignore
    File.writeAllBytes(outPath, buffer);
    return outPath;
}

function dumpFromMaps() {
    const modules = Process.enumerateModules();
    for (const { name, path } of modules) {
        if (filterSo({ name, path })) {
            if (!dumpedLibs.has(name)) {
                dumpLibInternal(name);
                dumpedLibs[name] = true;
            }
        }
    }
}

function initSoDump() {
    Inject.afterInitArrayModule(({ path, name }) => {
        if (filterSo({ name, path })) {
            logger.info(`path: ${path}, name: ${name}`);
            if (Libc.pthread_mutex_lock(mutex_addr) === 0x0) {
                try {
                    if (!dumpedLibs.has(name)) {
                        dumpLibInternal(name);
                        dumpedLibs[name] = true;
                    }
                } catch (error) {
                    logger.error(`dlopen(): ${error}`);
                } finally {
                    Libc.pthread_mutex_unlock(mutex_addr);
                }
            }
        } else if (name.includes('libc.so')) {
            if (Libc.pthread_mutex_lock(mutex_addr) === 0x0) {
                try {
                    dumpFromMaps();
                } catch (error) {
                    logger.error(`dumpFromMaps(): ${error}`);
                } finally {
                    Libc.pthread_mutex_unlock(mutex_addr);
                }
            }
        }
    });
}

function dumpLib(name: string, sync = false) {
    if (!sync || Libc.pthread_mutex_lock(mutex_addr) === 0x0) {
        try {
            dumpLibInternal(name);
        } catch (err) {
            logger.error(`dumpLib(sync=${sync}): ${err}`);
        } finally {
            sync && Libc.pthread_mutex_unlock(mutex_addr);
        }
    }
}

export { dumpLib, initSoDump };
